export const listContextData: "\n  query ListContextData(\n    $filter: ModelContextDataFilterInput\n    $limit: Int\n    $nextToken: String\n  ) {\n    listContextData(filter: $filter, limit: $limit, nextToken: $nextToken) {\n      items {\n        id\n        type\n        title\n        gradeLevel\n        weekNumber\n        ccssStandards\n        assessmentCode\n        isReference\n        nextStepLesson {\n          targetAssessmentCode\n          targetQuestionNumbers\n          topic\n          targetProblem\n          errorScenarios {\n            studentLabel\n            isCorrect\n            approach\n            reasoning\n            __typename\n          }\n          phases {\n            phaseName\n            durationMinutes\n            steps\n            teacherPrompts\n            __typename\n          }\n          keyTakeaways\n          independentProblems\n          exitTicket\n          __typename\n        }\n        exemplarQuestions {\n          questionNumber\n          questionText\n          ccssStandard\n          correctAnswer\n          pointValue\n          answerChoices {\n            label\n            text\n            __typename\n          }\n          misconceptions {\n            description\n            targetAnswer\n            __typename\n          }\n          sourceNote\n          __typename\n        }\n        strategy {\n          name\n          description\n          steps\n          applicableGrades\n          applicableStandards\n          examples\n          __typename\n        }\n        walkthroughData {\n          quarter\n          schools {\n            schoolCode\n            rubricScores\n            notes\n            __typename\n          }\n          __typename\n        }\n        createdAt\n        updatedAt\n        __typename\n      }\n      nextToken\n      __typename\n    }\n  }\n";
export const classroomsByClassroomName: "\n  query ClassroomsByClassroomName(\n    $classroomName: String!\n    $sortDirection: ModelSortDirection\n    $filter: ModelClassroomFilterInput\n    $limit: Int\n    $nextToken: String\n  ) {\n    classroomsByClassroomName(\n      classroomName: $classroomName\n      sortDirection: $sortDirection\n      filter: $filter\n      limit: $limit\n      nextToken: $nextToken\n    ) {\n      items {\n        id\n        classroomName\n        grade\n        subject\n        state\n        schoolYear\n        cohortSize\n        currentWeek\n        students {\n          items {\n            id\n            classroomId\n            name\n            externalId\n            performanceX\n            performanceY\n            confidenceLevel\n            status\n            createdAt\n            updatedAt\n            classroomStudentsId\n            __typename\n          }\n          nextToken\n          __typename\n        }\n        sessions {\n          items {\n            id\n            classroomId\n            sessionLabel\n            weekNumber\n            topic\n            ccssStandards\n            status\n            ppqAssessmentId\n            postPpqAssessmentId\n            assessments {\n              nextToken\n              __typename\n            }\n            misconceptions {\n              nextToken\n              __typename\n            }\n            pregeneratedNextSteps\n            createdAt\n            updatedAt\n            classroomSessionsId\n            __typename\n          }\n          nextToken\n          __typename\n        }\n        misconceptions {\n          items {\n            id\n            classroomId\n            sessionId\n            ccssStandard\n            title\n            description\n            aiReasoning\n            studentCount\n            studentPercent\n            severity\n            priority\n            occurrence\n            successIndicators\n            evidence {\n              source\n              mostCommonError\n              sampleStudentWork\n              aiThinkingPattern\n              __typename\n            }\n            prerequisiteGapCodes\n            impactedObjectiveCodes\n            activities {\n              nextToken\n              __typename\n            }\n            postPpqImprovement\n            createdAt\n            updatedAt\n            classroomMisconceptionsId\n            sessionMisconceptionsId\n            __typename\n          }\n          nextToken\n          __typename\n        }\n        savedNextSteps {\n          items {\n            id\n            classroomId\n            sessionId\n            activityId\n            status\n            completedAt\n            sortOrder\n            misconceptionId\n            misconceptionTitle\n            targetObjectiveStandard\n            priority\n            studentCount\n            studentPercent\n            occurrence\n            misconceptionSummary\n            successIndicators\n            activityTitle\n            activityTime\n            activityFormat\n            activitySummary\n            aiReasoning\n            evidence {\n              source\n              mostCommonError\n              sampleStudentWork\n              aiThinkingPattern\n              __typename\n            }\n            tabs {\n              __typename\n            }\n            createdAt\n            updatedAt\n            classroomSavedNextStepsId\n            __typename\n          }\n          nextToken\n          __typename\n        }\n        createdAt\n        updatedAt\n        __typename\n      }\n      nextToken\n      __typename\n    }\n  }\n";
export const sessionsByClassroomId: "\n  query SessionsByClassroomId(\n    $classroomId: ID!\n    $sortDirection: ModelSortDirection\n    $filter: ModelSessionFilterInput\n    $limit: Int\n    $nextToken: String\n  ) {\n    sessionsByClassroomId(\n      classroomId: $classroomId\n      sortDirection: $sortDirection\n      filter: $filter\n      limit: $limit\n      nextToken: $nextToken\n    ) {\n      items {\n        id\n        classroomId\n        sessionLabel\n        weekNumber\n        topic\n        ccssStandards\n        status\n        ppqAssessmentId\n        postPpqAssessmentId\n        assessments {\n          items {\n            id\n            classroomId\n            sessionId\n            assessmentCode\n            type\n            weekNumber\n            administeredAt\n            topic\n            ccssStandards\n            durationMinutes\n            calculatorAllowed\n            classPercentCorrect\n            questions {\n              questionNumber\n              questionType\n              correctAnswer\n              pointValue\n              ccssStandard\n              classPercentCorrect\n              __typename\n            }\n            studentResponses {\n              nextToken\n              __typename\n            }\n            sourceAssessmentId\n            createdAt\n            updatedAt\n            sessionAssessmentsId\n            __typename\n          }\n          nextToken\n          __typename\n        }\n        misconceptions {\n          items {\n            id\n            classroomId\n            sessionId\n            ccssStandard\n            title\n            description\n            aiReasoning\n            studentCount\n            studentPercent\n            severity\n            priority\n            occurrence\n            successIndicators\n            evidence {\n              source\n              mostCommonError\n              sampleStudentWork\n              aiThinkingPattern\n              __typename\n            }\n            prerequisiteGapCodes\n            impactedObjectiveCodes\n            activities {\n              nextToken\n              __typename\n            }\n            postPpqImprovement\n            createdAt\n            updatedAt\n            classroomMisconceptionsId\n            sessionMisconceptionsId\n            __typename\n          }\n          nextToken\n          __typename\n        }\n        pregeneratedNextSteps\n        createdAt\n        updatedAt\n        classroomSessionsId\n        __typename\n      }\n      nextToken\n      __typename\n    }\n  }\n";
